mapper.select:
SELECT id, request_id, community_id, user_id, user_name, user_role,
       user_ip, access_time, api_path, http_method, query_params,
       request_body, response_code, response_time, user_agent, create_time
FROM sys_access_log
WHERE 1=1

    AND community_id = #{communityId}


    AND user_id = #{userId}


    AND api_path LIKE CONCAT('%', #{apiPath}, '%')


    AND access_time >= #{startTime}


    AND access_time <= #{endTime}

ORDER BY access_time DESC
LIMIT 100

mapper.insert:
INSERT INTO sys_access_log_archive
SELECT * FROM sys_access_log
WHERE access_time < #{beforeDate}
LIMIT #{batchSize}

mapper.delete:
DELETE FROM sys_access_log
WHERE access_time < #{beforeDate}
LIMIT #{batchSize}
